	existingSessionID := generateSessionID(req.Namespace, req.Name, req.Kind)
	existing, err := s.store.GetSandboxBySessionID(ctx, existingSessionID)
	if err == nil && existing != nil {
		// Session exists, return existing
		c.JSON(http.StatusOK, CreateSandboxResponse{
