		// Rollback on failure
		s.k8sClient.DeleteSandbox(ctx, req.Namespace, req.Name)
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error:   "failed to store session",
			Code:    "STORE_ERROR",
			Details: err.Error(),
		})
		return
	}

	c.JSON(http.StatusOK, CreateSandboxResponse{
		SessionID: sessionID,
		Status:    status.Phase,
		Endpoint:  s.buildEndpoint(sandboxInfo),
		Namespace: req.Namespace,
		Name:      req.Name,
		Kind:      req.Kind,
		CreatedAt: now,
