	mu        sync.RWMutex
}

// NewMockKubernetesClient creates a new mock K8s client
func NewMockKubernetesClient() *MockKubernetesClient {
	return &MockKubernetesClient{
		sandboxes: make(map[string]*SandboxStatus),
	}
}

func (m *MockKubernetesClient) key(namespace, name string) string {
	return namespace + "/" + name
}

// CreateSandbox creates a mock sandbox
func (m *MockKubernetesClient) CreateSandbox(ctx context.Context, namespace, name, kind string, spec *SandboxSpec) (*SandboxStatus, error) {
	m.mu.Lock()
	defer m.mu.Unlock()

	key := m.key(namespace, name)
	status := &SandboxStatus{
		Phase:     "Pending",
		CreatedAt: time.Now(),
	}
	m.sandboxes[key] = status

	// Simulate async transition to Running
	go func() {
		time.Sleep(100 * time.Millisecond)
		m.mu.Lock()
		status.Phase = "Running"
		status.PodIP = "10.0.0." + strconv.Itoa(len(m.sandboxes)+100)
		status.StartedAt = time.Now()
		status.Endpoint = "http://" + status.PodIP + ":8080"
		m.mu.Unlock()
	}()

	return status, nil
}

// DeleteSandbox deletes a mock sandbox
func (m *MockKubernetesClient) DeleteSandbox(ctx context.Context, namespace, name string) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	key := m.key(namespace, name)
	delete(m.sandboxes, key)
	return nil
}

// GetSandboxStatus gets mock sandbox status
func (m *MockKubernetesClient) GetSandboxStatus(ctx context.Context, namespace, name string) (*SandboxStatus, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	key := m.key(namespace, name)
	if status, ok := m.sandboxes[key]; ok {
		return status, nil
	}
	return nil, fmt.Errorf("sandbox not found")
}

// WatchSandbox waits for sandbox to be ready
func (m *MockKubernetesClient) WatchSandbox(ctx context.Context, namespace, name string, timeout time.Duration) (*SandboxStatus, error) {
	key := m.key(namespace, name)
	deadline := time.Now().Add(timeout)

	for time.Now().Before(deadline) {
		m.mu.RLock()
		status, ok := m.sandboxes[key]
		m.mu.RUnlock()

		if ok && status.Phase == "Running" {
			return status, nil
		}

		time.Sleep(50 * time.Millisecond)
	}

	return nil, fmt.Errorf("timeout waiting for sandbox")
}

