	expiredSessions, err := s.store.ListExpiredSandboxes(ctx, now, gcBatchSize)
	if err != nil {
		fmt.Printf("GC error listing expired sessions: %v\n", err)
		return
	}

	for _, sessionID := range expiredSessions {
		sandbox, err := s.store.GetSandboxBySessionID(ctx, sessionID)
		if err != nil {
			continue
		}

		// Delete from K8s
		s.k8sClient.DeleteSandbox(ctx, sandbox.Namespace, sandbox.Name)
		// Delete from store
		s.store.DeleteSandboxBySessionID(ctx, sessionID)
		fmt.Printf("GC: deleted expired session %s\n", sessionID)
	}

	// Collect inactive sessions
	inactiveBefore := now.Add(-s.sessionTimeout)
	inactiveSessions, err := s.store.ListInactiveSandboxes(ctx, inactiveBefore, gcBatchSize)
	if err != nil {
		fmt.Printf("GC error listing inactive sessions: %v\n", err)
		return
	}

