}

// GetSandboxStatus gets mock sandbox status
func (m *MockKubernetesClient) GetSandboxStatus(ctx context.Context, namespace, name string) (*SandboxStatus, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	key := m.key(namespace, name)
	if status, ok := m.sandboxes[key]; ok {
		return status, nil
	}
	return nil, fmt.Errorf("sandbox not found")
}

// WatchSandbox waits for sandbox to be ready
func (m *MockKubernetesClient) WatchSandbox(ctx context.Context, namespace, name string, timeout time.Duration) (*SandboxStatus, error) {
	key := m.key(namespace, name)
	deadline := time.Now().Add(timeout)

	for time.Now().Before(deadline) {
		m.mu.RLock()
		status, ok := m.sandboxes[key]
		m.mu.RUnlock()

		if ok && status.Phase == "Running" {
			return status, nil
		}

		time.Sleep(50 * time.Millisecond)
	}

	return nil, fmt.Errorf("timeout waiting for sandbox")
}

