func main() {
	port := os.Getenv("PORT")
	if port == "" {
		port = defaultPort
	}

	// Initialize store
	storage, err := store.Storage()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to initialize store: %v\n", err)
		os.Exit(1)
	}

	// Initialize K8s client (mock for now, would be real implementation)
	k8sClient := NewMockKubernetesClient()

	// Create server
	server := NewServer(storage, k8sClient)

	// Start garbage collector
