// NewServer creates a new Workload Manager server
func NewServer(storage store.Store, k8sClient KubernetesClient) *Server {
	s := &Server{
		router:         gin.New(),
		store:          storage,
		k8sClient:      k8sClient,
		sessionTimeout: defaultSessionTimeout,
		maxSessionDur:  defaultMaxSessionDuration,
		gcStopCh:       make(chan struct{}),
	}

	// Configure middleware
	s.router.Use(gin.Recovery())
	s.router.Use(requestLogger())
	s.router.Use(corsMiddleware())

	// Health endpoint
	s.router.GET("/health", s.handleHealth)

	// API routes
	api := s.router.Group("/v1")
	{
		api.POST("/agent-runtime", s.handleCreateSandbox)
		api.POST("/code-interpreter", s.handleCreateSandbox)
		api.DELETE("/agent-runtime/sessions/:sessionId", s.handleDeleteSession)
		api.DELETE("/code-interpreter/sessions/:sessionId", s.handleDeleteSession)
	}

	return s
}

// handleHealth handles health check requests
func (s *Server) handleHealth(c *gin.Context) {
	// Check store connectivity
	if err := s.store.Ping(c.Request.Context()); err != nil {
		c.JSON(http.StatusServiceUnavailable, ErrorResponse{
			Error: "store unavailable",
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

// handleCreateSandbox handles sandbox creation requests
func (s *Server) handleCreateSandbox(c *gin.Context) {
	var req CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error:   "invalid request",
			Code:    "INVALID_REQUEST",
			Details: err.Error(),
		})
		return
	}

	// Derive kind from path
	if c.Request.URL.Path == "/v1/code-interpreter" {
		req.Kind = "CodeInterpreter"
	} else {
		req.Kind = "AgentRuntime"
	}

	ctx := c.Request.Context()

	// Check for existing session with same name (idempotency)
	existingSessionID := generateSessionID(req.Namespace, req.Name, req.Kind)
	existing, err := s.store.GetSandboxBySessionID(ctx, existingSessionID)
	if err == nil && existing != nil {
		// Session exists, return existing
		c.JSON(http.StatusOK, CreateSandboxResponse{
			SessionID: existing.SessionID,
			Status:    "exists",
			Endpoint:  s.buildEndpoint(existing),
			Namespace: existing.Namespace,
			Name:      existing.Name,
			Kind:      existing.Kind,
			CreatedAt: existing.CreatedAt,
			ExpiresAt: existing.ExpiresAt,
		})
		return
	}

	// Create sandbox in Kubernetes
	spec := &req.Spec
	if spec.Image == "" && req.Kind == "CodeInterpreter" {
		spec.Image = "picod:latest"
	}

	status, err := s.k8sClient.CreateSandbox(ctx, req.Namespace, req.Name, req.Kind, spec)
	if err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error:   "failed to create sandbox",
			Code:    "K8S_ERROR",
			Details: err.Error(),
		})
		return
	}

	// Wait for sandbox to be ready
	status, err = s.k8sClient.WatchSandbox(ctx, req.Namespace, req.Name, 2*time.Minute)
	if err != nil {
		// Rollback on failure
		s.k8sClient.DeleteSandbox(ctx, req.Namespace, req.Name)
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error:   "sandbox failed to start",
			Code:    "TIMEOUT",
			Details: err.Error(),
		})
		return
	}

	// Calculate TTL
	ttl := s.sessionTimeout
	if req.TTL > 0 {
		ttl = time.Duration(req.TTL) * time.Second
	}
	if ttl > s.maxSessionDur {
		ttl = s.maxSessionDur
	}

	now := time.Now()
	expiresAt := now.Add(ttl)

	// Store session info
	sessionID := generateSessionID(req.Namespace, req.Name, req.Kind)
	sandboxInfo := &store.SandboxInfo{
		SessionID:      sessionID,
		Namespace:      req.Namespace,
		Name:           req.Name,
		Kind:           req.Kind,
		PodIP:          status.PodIP,
		EntryPoints:    convertEntryPoints(req.Spec.Ports),
		ExpiresAt:      expiresAt,
		LastActivityAt: now,
		CreatedAt:      now,
	}

	if err := s.store.StoreSandbox(ctx, sandboxInfo); err != nil {
		// Rollback on failure
		s.k8sClient.DeleteSandbox(ctx, req.Namespace, req.Name)
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error:   "failed to store session",
			Code:    "STORE_ERROR",
			Details: err.Error(),
		})
		return
	}

	c.JSON(http.StatusOK, CreateSandboxResponse{
		SessionID: sessionID,
		Status:    status.Phase,
		Endpoint:  s.buildEndpoint(sandboxInfo),
		Namespace: req.Namespace,
		Name:      req.Name,
		Kind:      req.Kind,
		CreatedAt: now,
		ExpiresAt: expiresAt,
	})
}

// handleDeleteSession handles session deletion requests
func (s *Server) handleDeleteSession(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "missing session ID",
			Code:  "INVALID_REQUEST",
		})
		return
	}

	ctx := c.Request.Context()

	// Get session info
	sandbox, err := s.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			c.JSON(http.StatusNotFound, ErrorResponse{
				Error: "session not found",
				Code:  "NOT_FOUND",
			})
			return
		}
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error:   "failed to get session",
			Code:    "STORE_ERROR",
			Details: err.Error(),
		})
		return
	}

	// Delete from Kubernetes
	if err := s.k8sClient.DeleteSandbox(ctx, sandbox.Namespace, sandbox.Name); err != nil {
		// Log error but continue - K8s resource might already be gone
		fmt.Printf("Warning: failed to delete K8s sandbox: %v\n", err)
	}

	// Delete from store
	if err := s.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		c.JSON(http.StatusInternalServerError, ErrorResponse{
			Error:   "failed to delete session",
			Code:    "STORE_ERROR",
			Details: err.Error(),
		})
		return
	}

	c.Status(http.StatusNoContent)
}

// startGarbageCollector starts the background garbage collector
func (s *Server) startGarbageCollector() {
	s.gcWG.Add(1)
	go func() {
		defer s.gcWG.Done()
		ticker := time.NewTicker(gcInterval)
		defer ticker.Stop()

		for {
			select {
			case <-s.gcStopCh:
				return
			case <-ticker.C:
				s.runGarbageCollection()
			}
		}
	}()
}

// runGarbageCollection performs one garbage collection cycle
func (s *Server) runGarbageCollection() {
	ctx := context.Background()
	now := time.Now()

	// Collect expired sessions
	expiredSessions, err := s.store.ListExpiredSandboxes(ctx, now, gcBatchSize)
	if err != nil {
		fmt.Printf("GC error listing expired sessions: %v\n", err)
		return
	}

	for _, sessionID := range expiredSessions {
		sandbox, err := s.store.GetSandboxBySessionID(ctx, sessionID)
		if err != nil {
			continue
		}

		// Delete from K8s
		s.k8sClient.DeleteSandbox(ctx, sandbox.Namespace, sandbox.Name)
		// Delete from store
		s.store.DeleteSandboxBySessionID(ctx, sessionID)
		fmt.Printf("GC: deleted expired session %s\n", sessionID)
	}

	// Collect inactive sessions
	inactiveBefore := now.Add(-s.sessionTimeout)
	inactiveSessions, err := s.store.ListInactiveSandboxes(ctx, inactiveBefore, gcBatchSize)
	if err != nil {
		fmt.Printf("GC error listing inactive sessions: %v\n", err)
		return
	}

	for _, sessionID := range inactiveSessions {
		sandbox, err := s.store.GetSandboxBySessionID(ctx, sessionID)
		if err != nil {
			continue
		}

		// Delete from K8s
		s.k8sClient.DeleteSandbox(ctx, sandbox.Namespace, sandbox.Name)
		// Delete from store
		s.store.DeleteSandboxBySessionID(ctx, sessionID)
		fmt.Printf("GC: deleted inactive session %s\n", sessionID)
	}
}

// shutdown gracefully shuts down the server
func (s *Server) shutdown() {
	close(s.gcStopCh)
	s.gcWG.Wait()
	s.store.Close()
}

// buildEndpoint builds the endpoint URL from sandbox info
func (s *Server) buildEndpoint(sandbox *store.SandboxInfo) string {
	if len(sandbox.EntryPoints) == 0 {
		return fmt.Sprintf("http://%s:8080", sandbox.PodIP)
	}
	ep := sandbox.EntryPoints[0]
	return fmt.Sprintf("http://%s:%d%s", sandbox.PodIP, ep.Port, ep.PathPrefix)
}

// generateSessionID generates a unique session ID
func generateSessionID(namespace, name, kind string) string {
	return fmt.Sprintf("%s-%s-%s", namespace, name, kind)
}

// convertEntryPoints converts port specs to entry points
func convertEntryPoints(ports []PortSpec) []store.EntryPoint {
	var entryPoints []store.EntryPoint
	for _, p := range ports {
		entryPoints = append(entryPoints, store.EntryPoint{
			Port:       p.Port,
			Protocol:   p.Protocol,
			PathPrefix: p.PathPrefix,
		})
	}
	return entryPoints
}

// requestLogger returns a logging middleware
func requestLogger() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path
		raw := c.Request.URL.RawQuery

		c.Next()

		latency := time.Since(start)
		clientIP := c.ClientIP()
		method := c.Request.Method
		statusCode := c.Writer.Status()

		if raw != "" {
			path = path + "?" + raw
		}

		fmt.Printf("[WorkloadManager] %s | %3d | %13v | %15s | %-7s %s\n",
			start.Format("2006/01/02 - 15:04:05"),
			statusCode,
			latency,
			clientIP,
			method,
			path,
		)
	}
}

// corsMiddleware returns a CORS middleware
func corsMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		c.Writer.Header().Set("Access-Control-Allow-Origin", "*")
		c.Writer.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
		c.Writer.Header().Set("Access-Control-Allow-Headers", "Origin, Content-Type, Accept, Authorization")

		if c.Request.Method == "OPTIONS" {
			c.AbortWithStatus(204)
			return
		}

		c.Next()
	}
}

// MockKubernetesClient is a mock implementation for testing
type MockKubernetesClient struct {
	sandboxes map[string]*SandboxStatus
	mu        sync.RWMutex
	createErr error
}

// NewMockKubernetesClient creates a new mock K8s client
func NewMockKubernetesClient() *MockKubernetesClient {
	return &MockKubernetesClient{
		sandboxes: make(map[string]*SandboxStatus),
	}
}

func (m *MockKubernetesClient) key(namespace, name string) string {
	return namespace + "/" + name
}

// CreateSandbox creates a mock sandbox
func (m *MockKubernetesClient) CreateSandbox(ctx context.Context, namespace, name, kind string, spec *SandboxSpec) (*SandboxStatus, error) {
	m.mu.Lock()
	defer m.mu.Unlock()

	if m.createErr != nil {
		return nil, m.createErr
	}

	key := m.key(namespace, name)
	status := &SandboxStatus{
		Phase:     "Pending",
		CreatedAt: time.Now(),
	}
	m.sandboxes[key] = status

	// Simulate async transition to Running
	go func() {
		time.Sleep(100 * time.Millisecond)
		m.mu.Lock()
		status.Phase = "Running"
		status.PodIP = "10.0.0." + strconv.Itoa(len(m.sandboxes)+100)
		status.StartedAt = time.Now()
		status.Endpoint = "http://" + status.PodIP + ":8080"
		m.mu.Unlock()
	}()

	return status, nil
}

// DeleteSandbox deletes a mock sandbox
func (m *MockKubernetesClient) DeleteSandbox(ctx context.Context, namespace, name string) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	key := m.key(namespace, name)
	delete(m.sandboxes, key)
	return nil
}

// GetSandboxStatus gets mock sandbox status
func (m *MockKubernetesClient) GetSandboxStatus(ctx context.Context, namespace, name string) (*SandboxStatus, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	key := m.key(namespace, name)
	if status, ok := m.sandboxes[key]; ok {
		return status, nil
	}
	return nil, fmt.Errorf("sandbox not found")
}

// WatchSandbox waits for sandbox to be ready
func (m *MockKubernetesClient) WatchSandbox(ctx context.Context, namespace, name string, timeout time.Duration) (*SandboxStatus, error) {
	key := m.key(namespace, name)
	deadline := time.Now().Add(timeout)

	for time.Now().Before(deadline) {
		m.mu.RLock()
		status, ok := m.sandboxes[key]
		m.mu.RUnlock()

		if ok && status.Phase == "Running" {
			return status, nil
		}

		time.Sleep(50 * time.Millisecond)
	}

	return nil, fmt.Errorf("timeout waiting for sandbox")
}

