// Package main implements the AgentCube Session Router.
// It routes HTTP requests to sandbox pods based on session IDs.
package main

import (
	"context"
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"os"
	"os/signal"
	"strconv"
	"strings"
	"syscall"
	"time"

	"github.com/agentcube/agentcube/pkg/router"
	"github.com/agentcube/agentcube/pkg/store"
	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

const (
	defaultPort           = "8080"
	defaultWorkloadMgrURL = "http://localhost:8081"
	defaultMaxConcurrent  = 1000
)

// Server represents the Router HTTP server
type Server struct {
	router          *gin.Engine
	store           store.Store
	sessionManager  *router.SessionManager
	proxyHandler    *ProxyHandler
	workloadMgrURL  string
	maxConcurrent   int
}

// ProxyHandler wraps the router.ProxyHandler for local use
type ProxyHandler struct {
	baseHandler    *router.ProxyHandler
	errorHandler   *router.ErrorHandler
}

// NewProxyHandler creates a new proxy handler
func NewProxyHandler(sm *router.SessionManager) *ProxyHandler {
	return &ProxyHandler{
		baseHandler:  router.NewProxyHandler(sm),
		errorHandler: &router.ErrorHandler{},
	}
}

// HandleProxy handles proxy requests with error mapping
func (ph *ProxyHandler) HandleProxy(c *gin.Context) {
	ph.baseHandler.HandleProxy(c)
}

func main() {
	port := os.Getenv("PORT")
	if port == "" {
		port = defaultPort
	}

	workloadMgrURL := os.Getenv("WORKLOAD_MANAGER_URL")
	if workloadMgrURL == "" {
		workloadMgrURL = defaultWorkloadMgrURL
	}

	maxConcurrent := defaultMaxConcurrent
	if mc := os.Getenv("MAX_CONCURRENT"); mc != "" {
		if val, err := strconv.Atoi(mc); err == nil {
			maxConcurrent = val
		}
	}

	// Initialize store
	storage, err := store.Storage()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to initialize store: %v\n", err)
		os.Exit(1)
	}

	// Create server
	server := NewServer(storage, workloadMgrURL, maxConcurrent)

	// Setup graceful shutdown
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-sigCh
		fmt.Println("Shutting down gracefully...")
		server.shutdown()
		os.Exit(0)
	}()

	fmt.Printf("Router starting on port %s\n", port)
	fmt.Printf("Workload Manager URL: %s\n", workloadMgrURL)
	fmt.Printf("Max Concurrent: %d\n", maxConcurrent)

	if err := server.router.Run(":" + port); err != nil {
		fmt.Fprintf(os.Stderr, "Server error: %v\n", err)
		os.Exit(1)
	}
}

// NewServer creates a new Router server
func NewServer(storage store.Store, workloadMgrURL string, maxConcurrent int) *Server {
	gin.SetMode(gin.ReleaseMode)

	s := &Server{
		router:         gin.New(),
		store:          storage,
		workloadMgrURL: workloadMgrURL,
		maxConcurrent:  maxConcurrent,
	}

	// Create session manager
	s.sessionManager = router.NewSessionManager(storage, workloadMgrURL)

	// Create proxy handler
	s.proxyHandler = NewProxyHandler(s.sessionManager)

	// Configure middleware chain (order matters!)
	s.router.Use(gin.Recovery())
	s.router.Use(requestIDMiddleware())
	s.router.Use(requestLogger())
	s.router.Use(metricsMiddleware())
	s.router.Use(authMiddleware(storage))
	s.router.Use(concurrencyLimiter(maxConcurrent))
	s.router.Use(corsMiddleware())

	// Health endpoints
	s.router.GET("/health/live", s.handleLiveness)
	s.router.GET("/health/ready", s.handleReadiness)

	// Proxy routes
	s.router.GET("/v1/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.proxyHandler.HandleProxy)
	s.router.POST("/v1/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.proxyHandler.HandleProxy)
	s.router.GET("/v1/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.proxyHandler.HandleProxy)
	s.router.POST("/v1/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.proxyHandler.HandleProxy)

	return s
}

// handleLiveness handles liveness probe
func (s *Server) handleLiveness(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

// handleReadiness handles readiness probe
func (s *Server) handleReadiness(c *gin.Context) {
	if err := s.store.Ping(c.Request.Context()); err != nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  "store unavailable",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

// shutdown gracefully shuts down the server
func (s *Server) shutdown() {
	s.store.Close()
}

// requestIDMiddleware injects X-Request-ID for tracing
func requestIDMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		requestID := c.GetHeader("X-Request-ID")
		if requestID == "" {
			requestID = generateRequestID()
		}
		c.Set("request_id", requestID)
		c.Header("X-Request-ID", requestID)
		c.Next()
	}
}

// generateRequestID generates a unique request ID
func generateRequestID() string {
	return fmt.Sprintf("%d-%d", time.Now().UnixNano(), os.Getpid())
}

// requestLogger logs requests
func requestLogger() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path
		raw := c.Request.URL.RawQuery

		c.Next()

		latency := time.Since(start)
		clientIP := c.ClientIP()
		method := c.Request.Method
		statusCode := c.Writer.Status()
		requestID := c.GetString("request_id")

		if raw != "" {
			path = path + "?" + raw
		}

		fmt.Printf("[Router] %s | %s | %3d | %13v | %15s | %-7s %s\n",
			requestID,
			start.Format("2006/01/02 - 15:04:05"),
			statusCode,
			latency,
			clientIP,
			method,
			path,
		)
	}
}

// metricsMiddleware records Prometheus metrics
func metricsMiddleware() gin.HandlerFunc {
	// In production, this would use Prometheus client
	requestCount := make(map[string]int)
	requestLatency := make(map[string]time.Duration)

	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := strconv.Itoa(c.Writer.Status())

		// Simple metrics tracking (would be Prometheus in production)
		key := path + ":" + status
		requestCount[key]++
		requestLatency[key] += latency
	}
}

// authMiddleware validates Bearer tokens
func authMiddleware(storage store.Store) gin.HandlerFunc {
	return func(c *gin.Context) {
		// Skip auth for health endpoints
		if strings.HasPrefix(c.Request.URL.Path, "/health") {
			c.Next()
			return
		}

		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error": "missing authorization header",
			})
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error": "invalid authorization header",
			})
			return
		}

		token := parts[1]

		// Validate JWT
		if !validateToken(token) {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error": "invalid token",
			})
			return
		}

		c.Next()
	}
}

// validateToken validates a JWT token
func validateToken(tokenString string) bool {
	// Parse without verification (in production, use proper key)
	token, _, err := new(jwt.Parser).ParseUnverified(tokenString, jwt.MapClaims{})
	if err != nil {
		return false
	}

	if claims, ok := token.Claims.(jwt.MapClaims); ok {
		if exp, ok := claims["exp"].(float64); ok {
			return time.Now().Unix() < int64(exp)
		}
	}

	return false
}

// concurrencyLimiter limits concurrent requests using semaphore
func concurrencyLimiter(maxConcurrent int) gin.HandlerFunc {
	if maxConcurrent <= 0 {
		maxConcurrent = defaultMaxConcurrent
	}
	semaphore := make(chan struct{}, maxConcurrent)

	return func(c *gin.Context) {
		select {
		case semaphore <- struct{}{}:
			defer func() {
				select {
				case <-semaphore:
				default:
				}
			}()
			c.Next()
		default:
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error": "too many concurrent requests",
			})
		}
	}
}

// corsMiddleware returns CORS headers
func corsMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		c.Writer.Header().Set("Access-Control-Allow-Origin", "*")
		c.Writer.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
		c.Writer.Header().Set("Access-Control-Allow-Headers", "Origin, Content-Type, Accept, Authorization, X-AgentCube-Session-ID, X-Request-ID")

		if c.Request.Method == "OPTIONS" {
			c.AbortWithStatus(204)
			return
		}

		c.Next()
	}
}

// ForwardingHeaders contains headers for proxy forwarding
type ForwardingHeaders struct {
	XForwardedHost  string
	XForwardedProto string
	XForwardedFor   string
}

// NewSingleHostReverseProxy creates a reverse proxy with custom headers
func NewSingleHostReverseProxy(target *url.URL) *httputil.ReverseProxy {
	director := func(req *http.Request) {
		req.URL.Scheme = target.Scheme
		req.URL.Host = target.Host
		req.Host = target.Host

		if target.Path == "" {
			target.Path = "/"
		}

		if req.URL.Path == "" {
			req.URL.Path = target.Path
		} else {
			req.URL.Path = target.Path + req.URL.Path
		}
	}

	return &httputil.ReverseProxy{Director: director}
}

// SessionInfo represents session information
type SessionInfo struct {
	SessionID      string    `json:"session_id"`
	Namespace      string    `json:"namespace"`
	Name           string    `json:"name"`
	Kind           string    `json:"kind"`
	Endpoint       string    `json:"endpoint"`
	LastActivityAt time.Time `json:"last_activity_at"`
}

// ErrorCode represents error codes for router errors
type ErrorCode string

const (
	ErrCodeUnauthorized     ErrorCode = "UNAUTHORIZED"
	ErrCodeSessionNotFound  ErrorCode = "SESSION_NOT_FOUND"
	ErrCodeSandboxTimeout   ErrorCode = "SANDBOX_TIMEOUT"
	ErrCodeSandboxUnreachable ErrorCode = "SANDBOX_UNREACHABLE"
	ErrCodeTooManyRequests  ErrorCode = "TOO_MANY_REQUESTS"
)

