func (sa *storeAdapter) GetSandboxBySessionID(ctx context.Context, sessionID string) (*router.SandboxInfo, error) {
	sandbox, err := sa.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		return nil, err
	}

	// Convert store.SandboxInfo to router.SandboxInfo
	entryPoints := make([]router.EntryPoint, len(sandbox.EntryPoints))
	for i, ep := range sandbox.EntryPoints {
