			PathPrefix: ep.PathPrefix,
		}
	}

	return &router.SandboxInfo{
		SessionID:      sandbox.SessionID,
		Namespace:      sandbox.Namespace,
		Name:           sandbox.Name,
		Kind:           sandbox.Kind,
		PodIP:          sandbox.PodIP,
		EntryPoints:    entryPoints,
		LastActivityAt: sandbox.LastActivityAt,
	}, nil
}

