	return nil
}

func (m *MockStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	return nil, nil
}

func (m *MockStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	return nil, nil
}

func (m *MockStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	return nil
}

func (m *MockStore) Close() error {
	return nil
}

func setupTestRouterServer(t *testing.T) (*Server, *MockStore) {
	gin.SetMode(gin.TestMode)
	mockStore := NewMockStore()
	server := NewServer(mockStore, "http://localhost:8081", 1000)
	return server, mockStore
}

// generateTestToken generates a valid test JWT token
func generateTestToken(sessionID string, exp time.Time) string {
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, jwt.MapClaims{
		"session_id": sessionID,
		"exp":        exp.Unix(),
	})
	tokenString, _ := token.SignedString([]byte("test-secret"))
	return tokenString
}

// generateExpiredToken generates an expired JWT token
func generateExpiredToken() string {
	return generateTestToken("test", time.Now().Add(-time.Hour))
}

// generateValidToken generates a valid JWT token
func generateValidToken() string {
	return generateTestToken("test", time.Now().Add(time.Hour))
}

// Test-RT-1: Auth Middleware - illegal JWT returns 401
func TestAuthMiddleware_InvalidJWT(t *testing.T) {
	server, _ := setupTestRouterServer(t)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/v1/namespaces/default/agent-runtimes/test/invocations/api", nil)
	req.Header.Set("Authorization", "Bearer invalid.token.here")
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusUnauthorized, w.Code)

	var response map[string]string
	err := json.Unmarshal(w.Body.Bytes(), &response)
	require.NoError(t, err)
	assert.Contains(t, response["error"], "invalid token")
}

// Test-RT-1: Auth Middleware - missing token returns 401
func TestAuthMiddleware_MissingToken(t *testing.T) {
	server, _ := setupTestRouterServer(t)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/v1/namespaces/default/agent-runtimes/test/invocations/api", nil)
	// No Authorization header
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusUnauthorized, w.Code)

	var response map[string]string
	err := json.Unmarshal(w.Body.Bytes(), &response)
	require.NoError(t, err)
	assert.Contains(t, response["error"], "missing authorization")
}

// Test-RT-2: Expired JWT returns Token Expired
func TestAuthMiddleware_ExpiredJWT(t *testing.T) {
	server, _ := setupTestRouterServer(t)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/v1/namespaces/default/agent-runtimes/test/invocations/api", nil)
	req.Header.Set("Authorization", "Bearer "+generateExpiredToken())
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusUnauthorized, w.Code)
}

// Test-RT-3: Proxy timeout handling - Gateway Timeout
func TestProxyHandler_Timeout(t *testing.T) {
	server, mockStore := setupTestRouterServer(t)

	// Add a sandbox session
	sessionID := "default-test-AgentRuntime"
	mockStore.sandboxes[sessionID] = &store.SandboxInfo{
		SessionID:      sessionID,
		Namespace:      "default",
		Name:           "test",
		Kind:           "AgentRuntime",
		PodIP:          "127.0.0.1",
		EntryPoints:    []store.EntryPoint{{Port: 9999, Protocol: "HTTP", PathPrefix: "/"}},
		LastActivityAt: time.Now(),
	}

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/v1/namespaces/default/agent-runtimes/test/invocations/api", nil)
	req.Header.Set("Authorization", "Bearer "+generateValidToken())
	req.Header.Set("X-AgentCube-Session-ID", sessionID)
	server.router.ServeHTTP(w, req)

	// Should get 502/504 due to connection refused/timeout
	assert.True(t, w.Code == http.StatusBadGateway || w.Code == http.StatusGatewayTimeout || w.Code == http.StatusOK)
}

// Test-RT-4: Header forwarding - Host, X-Forwarded-For, etc.
func TestProxyHandler_HeaderForwarding(t *testing.T) {
	server, mockStore := setupTestRouterServer(t)

	sessionID := "default-test-AgentRuntime"
	mockStore.sandboxes[sessionID] = &store.SandboxInfo{
		SessionID:      sessionID,
		Namespace:      "default",
		Name:           "test",
		Kind:           "AgentRuntime",
		PodIP:          "10.0.0.1",
		EntryPoints:    []store.EntryPoint{{Port: 8080, Protocol: "HTTP", PathPrefix: "/"}},
		LastActivityAt: time.Now(),
	}

	// This test verifies headers are set properly by checking they exist
	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/v1/namespaces/default/agent-runtimes/test/invocations/api", nil)
	req.Header.Set("Authorization", "Bearer "+generateValidToken())
