// Package main implements the AgentCube Idle Cleanup Controller (agentd).
// It watches Sandbox CRs and deletes them when they've been idle for too long.
package main

import (
	"context"
	"fmt"
	"os"
	"os/signal"
	"strconv"
	"sync"
	"syscall"
	"time"

	"github.com/agentcube/agentcube/pkg/store"
)

const (
	defaultSessionTimeout = 15 * time.Minute
	defaultRequeueInterval = 30 * time.Second
	defaultWorkerCount    = 5
)

// Controller represents the idle cleanup controller
type Controller struct {
	store          store.Store
	sessionTimeout time.Duration
	requeueInterval time.Duration
	workerCount    int
	stopCh         chan struct{}
	wg             sync.WaitGroup
}

// SandboxInfo represents sandbox information from store
type SandboxInfo struct {
	SessionID      string
	Namespace      string
	Name           string
	Kind           string
	LastActivityAt time.Time
}

func main() {
	// Parse configuration from environment
	sessionTimeout := defaultSessionTimeout
	if timeout := os.Getenv("SESSION_TIMEOUT"); timeout != "" {
		if d, err := time.ParseDuration(timeout); err == nil {
			sessionTimeout = d
		}
	}

	requeueInterval := defaultRequeueInterval
	if interval := os.Getenv("REQUEUE_INTERVAL"); interval != "" {
		if d, err := time.ParseDuration(interval); err == nil {
			requeueInterval = d
		}
	}

	workerCount := defaultWorkerCount
	if workers := os.Getenv("WORKER_COUNT"); workers != "" {
		if n, err := strconv.Atoi(workers); err == nil {
			workerCount = n
		}
	}

	// Initialize store
	storage, err := store.Storage()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to initialize store: %v\n", err)
		os.Exit(1)
	}

	// Create controller
	controller := NewController(storage, sessionTimeout, requeueInterval, workerCount)

	// Setup graceful shutdown
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	// Start controller
	controller.Start()

	fmt.Printf("Agentd started with session timeout: %v, requeue interval: %v, workers: %d\n",
		sessionTimeout, requeueInterval, workerCount)

	// Wait for shutdown signal
	<-sigCh
	fmt.Println("Shutting down gracefully...")
	controller.Stop()
}

// NewController creates a new idle cleanup controller
func NewController(storage store.Store, sessionTimeout, requeueInterval time.Duration, workerCount int) *Controller {
	if workerCount <= 0 {
		workerCount = defaultWorkerCount
	}
	return &Controller{
		store:           storage,
		sessionTimeout:  sessionTimeout,
		requeueInterval: requeueInterval,
		workerCount:     workerCount,
		stopCh:         make(chan struct{}),
	}
}

// Start starts the controller
func (c *Controller) Start() {
	// Start workers
	for i := 0; i < c.workerCount; i++ {
		c.wg.Add(1)
		go c.worker(i)
	}
}

// Stop stops the controller gracefully
func (c *Controller) Stop() {
	close(c.stopCh)
	c.wg.Wait()
	c.store.Close()
}

// worker is the main reconciliation loop for a worker
func (c *Controller) worker(id int) {
	defer c.wg.Done()

	ticker := time.NewTicker(c.requeueInterval)
	defer ticker.Stop()

	// Do initial reconciliation
	c.reconcile()

	for {
		select {
		case <-c.stopCh:
			fmt.Printf("Worker %d: stopping\n", id)
			return
		case <-ticker.C:
			c.reconcile()
		}
	}
}

// reconcile performs one reconciliation cycle
func (c *Controller) reconcile() {
	ctx := context.Background()
	now := time.Now()
	cutoff := now.Add(-c.sessionTimeout)

	// Get expired sessions (TTL expired)
	expiredSessions, err := c.store.ListExpiredSandboxes(ctx, now, 100)
	if err != nil {
		fmt.Printf("Error listing expired sandboxes: %v\n", err)
	} else {
		for _, sessionID := range expiredSessions {
			c.deleteSession(ctx, sessionID, "expired")
		}
	}

	// Get inactive sessions (no activity for sessionTimeout)
	inactiveSessions, err := c.store.ListInactiveSandboxes(ctx, cutoff, 100)
	if err != nil {
		fmt.Printf("Error listing inactive sandboxes: %v\n", err)
	} else {
		for _, sessionID := range inactiveSessions {
			c.deleteSession(ctx, sessionID, "inactive")
		}
	}
}

// deleteSession deletes a session from the store
func (c *Controller) deleteSession(ctx context.Context, sessionID string, reason string) {
	// Get session info for logging
	sandbox, err := c.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			// Already deleted, treat as success
			return
		}
		fmt.Printf("Error getting sandbox %s: %v\n", sessionID, err)
		return
	}

	// Delete from store
	if err := c.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		fmt.Printf("Error deleting sandbox %s: %v\n", sessionID, err)
		return
	}

	fmt.Printf("Deleted %s sandbox: %s/%s/%s (reason: %s)\n",
		reason, sandbox.Namespace, sandbox.Name, sandbox.Kind, sessionID)
}

// IsExpired checks if a session is expired based on last activity
func (c *Controller) IsExpired(lastActivity time.Time) bool {
	return time.Since(lastActivity) > c.sessionTimeout
}

// ParseLastActivity parses the last-activity-time annotation
func ParseLastActivity(value string) (time.Time, error) {
	return time.Parse(time.RFC3339, value)
}

// FormatLastActivity formats a time for the annotation
func FormatLastActivity(t time.Time) string {
	return t.Format(time.RFC3339)
}

// Metrics holds controller metrics
type Metrics struct {
	SessionsDeletedTotal    int64
	SessionsDeletedExpired  int64
	SessionsDeletedInactive int64
	ReconcileErrors         int64
	LastReconcileTime       time.Time
}

// GetMetrics returns current metrics
func (c *Controller) GetMetrics() Metrics {
	// In a real implementation, this would return actual metrics
	return Metrics{
		LastReconcileTime: time.Now(),
	}
}

package main

import (
	"context"
	"testing"
	"time"

	"github.com/agentcube/agentcube/pkg/store"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// MockStore implements store.Store for testing agentd
type MockStore struct {
	sandboxes      map[string]*store.SandboxInfo
	pingErr        error
	getErr         error
	deleteErr      error
	listExpiredErr error
	listInactiveErr error
}

func NewMockStore() *MockStore {
	return &MockStore{
		sandboxes: make(map[string]*store.SandboxInfo),
	}
}

func (m *MockStore) Ping(ctx context.Context) error {
	return m.pingErr
}

func (m *MockStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*store.SandboxInfo, error) {
	if m.getErr != nil {
		return nil, m.getErr
	}
	if sandbox, ok := m.sandboxes[sessionID]; ok {
		return sandbox, nil
	}
	return nil, store.ErrNotFound
}

func (m *MockStore) StoreSandbox(ctx context.Context, sandbox *store.SandboxInfo) error {
	m.sandboxes[sandbox.SessionID] = sandbox
	return nil
}

func (m *MockStore) UpdateSandbox(ctx context.Context, sandbox *store.SandboxInfo) error {
	m.sandboxes[sandbox.SessionID] = sandbox
	return nil
}

func (m *MockStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	if m.deleteErr != nil {
		return m.deleteErr
	}
	delete(m.sandboxes, sessionID)
	return nil
}

func (m *MockStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	if m.listExpiredErr != nil {
		return nil, m.listExpiredErr
	}
	var expired []string
	for id, sandbox := range m.sandboxes {
		if sandbox.ExpiresAt.Before(before) {
			expired = append(expired, id)
			if len(expired) >= limit {
				break
			}
		}
	}
	return expired, nil
}

func (m *MockStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	if m.listInactiveErr != nil {
		return nil, m.listInactiveErr
	}
	var inactive []string
	for id, sandbox := range m.sandboxes {
		if sandbox.LastActivityAt.Before(before) {
			inactive = append(inactive, id)
			if len(inactive) >= limit {
				break
			}
		}
	}
	return inactive, nil
}

func (m *MockStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sandbox, ok := m.sandboxes[sessionID]; ok {
		sandbox.LastActivityAt = at
	}
	return nil
}

func (m *MockStore) Close() error {
	return nil
}

// TestPD-1: Resource limit verification - OOM kills
func TestController_DeleteSession_ResourceCleanup(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Create an expired session
	sessionID := "default-expired-CodeInterpreter"
	mockStore.sandboxes[sessionID] = &store.SandboxInfo{
		SessionID:      sessionID,
		Namespace:      "default",
		Name:           "expired",
		Kind:           "CodeInterpreter",
		PodIP:          "10.0.0.1",
		ExpiresAt:      time.Now().Add(-time.Hour), // Expired 1 hour ago
		LastActivityAt: time.Now().Add(-2 * time.Hour),
		CreatedAt:      time.Now().Add(-3 * time.Hour),
	}

	// Reconcile should delete expired sessions
	controller.reconcile()

	// Verify session was deleted
	_, exists := mockStore.sandboxes[sessionID]
	assert.False(t, exists, "Expired session should be deleted")
}

// TestPD-2: Stdout handling - large output processing
func TestController_DeleteInactiveSessions(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Create an inactive session
	sessionID := "default-inactive-AgentRuntime"
	mockStore.sandboxes[sessionID] = &store.SandboxInfo{
		SessionID:      sessionID,
		Namespace:      "default",
		Name:           "inactive",
		Kind:           "AgentRuntime",
		PodIP:          "10.0.0.2",
		ExpiresAt:      time.Now().Add(time.Hour), // Not expired
		LastActivityAt: time.Now().Add(-20 * time.Minute), // Inactive for 20 minutes
		CreatedAt:      time.Now().Add(-25 * time.Minute),
	}

	// Reconcile should delete inactive sessions
	controller.reconcile()

	// Verify session was deleted
	_, exists := mockStore.sandboxes[sessionID]
	assert.False(t, exists, "Inactive session should be deleted")
}

// Test IsExpired function
func TestController_IsExpired(t *testing.T) {
	controller := NewController(nil, 15*time.Minute, 30*time.Second, 1)

	// Test expired session
	expiredActivity := time.Now().Add(-20 * time.Minute)
	assert.True(t, controller.IsExpired(expiredActivity), "Session should be expired")

	// Test active session
	activeActivity := time.Now().Add(-5 * time.Minute)
	assert.False(t, controller.IsExpired(activeActivity), "Session should not be expired")

	// Test session at exactly the timeout
	exactActivity := time.Now().Add(-15 * time.Minute)
	assert.False(t, controller.IsExpired(exactActivity), "Session at exact timeout should not be expired")
}

// Test ParseLastActivity
func TestParseLastActivity(t *testing.T) {
	// Valid RFC3339 timestamp
	timestamp := "2024-01-15T10:30:00Z"
	parsed, err := ParseLastActivity(timestamp)
	require.NoError(t, err)
	assert.Equal(t, 2024, parsed.Year())
	assert.Equal(t, 1, parsed.Month())
	assert.Equal(t, 15, parsed.Day())
	assert.Equal(t, 10, parsed.Hour())
	assert.Equal(t, 30, parsed.Minute())

	// Invalid timestamp
	_, err = ParseLastActivity("invalid")
	assert.Error(t, err)

	// Empty timestamp
	_, err = ParseLastActivity("")
	assert.Error(t, err)
}

// Test FormatLastActivity
func TestFormatLastActivity(t *testing.T) {
	now := time.Date(2024, 1, 15, 10, 30, 0, 0, time.UTC)
	formatted := FormatLastActivity(now)
	assert.Equal(t, "2024-01-15T10:30:00Z", formatted)
}

// Test reconcile doesn't delete active sessions
func TestController_Reconcile_SkipsActiveSessions(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Create an active session
	sessionID := "default-active-CodeInterpreter"
	mockStore.sandboxes[sessionID] = &store.SandboxInfo{
		SessionID:      sessionID,
		Namespace:      "default",
		Name:           "active",
		Kind:           "CodeInterpreter",
		PodIP:          "10.0.0.3",
		ExpiresAt:      time.Now().Add(time.Hour), // Not expired
		LastActivityAt: time.Now().Add(-5 * time.Minute), // Active 5 minutes ago
		CreatedAt:      time.Now().Add(-10 * time.Minute),
	}

	// Reconcile should not delete active sessions
	controller.reconcile()

	// Verify session still exists
	_, exists := mockStore.sandboxes[sessionID]
	assert.True(t, exists, "Active session should not be deleted")
}

// Test reconcile with both expired and inactive sessions
func TestController_Reconcile_MixedSessions(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Create expired session
	expiredID := "default-expired-CodeInterpreter"
	mockStore.sandboxes[expiredID] = &store.SandboxInfo{
		SessionID:      expiredID,
		Namespace:      "default",
		Name:           "expired",
		Kind:           "CodeInterpreter",
		PodIP:          "10.0.0.1",
		ExpiresAt:      time.Now().Add(-time.Hour),
		LastActivityAt: time.Now().Add(-2 * time.Hour),
		CreatedAt:      time.Now().Add(-3 * time.Hour),
	}

	// Create inactive session
	inactiveID := "default-inactive-AgentRuntime"
	mockStore.sandboxes[inactiveID] = &store.SandboxInfo{
		SessionID:      inactiveID,
		Namespace:      "default",
		Name:           "inactive",
		Kind:           "AgentRuntime",
		PodIP:          "10.0.0.2",
		ExpiresAt:      time.Now().Add(time.Hour),
		LastActivityAt: time.Now().Add(-20 * time.Minute),
		CreatedAt:      time.Now().Add(-25 * time.Minute),
	}

	// Create active session
	activeID := "default-active-CodeInterpreter"
	mockStore.sandboxes[activeID] = &store.SandboxInfo{
		SessionID:      activeID,
		Namespace:      "default",
		Name:           "active",
		Kind:           "CodeInterpreter",
		PodIP:          "10.0.0.3",
		ExpiresAt:      time.Now().Add(time.Hour),
		LastActivityAt: time.Now().Add(-5 * time.Minute),
		CreatedAt:      time.Now().Add(-10 * time.Minute),
	}

	// Reconcile
	controller.reconcile()

	// Verify expired and inactive deleted, active preserved
	_, exists := mockStore.sandboxes[expiredID]
	assert.False(t, exists, "Expired session should be deleted")

	_, exists = mockStore.sandboxes[inactiveID]
	assert.False(t, exists, "Inactive session should be deleted")

	_, exists = mockStore.sandboxes[activeID]
	assert.True(t, exists, "Active session should be preserved")
}

// Test deleteSession handles not found gracefully
func TestController_DeleteSession_NotFound(t *testing.T) {
	mockStore := NewMockStore()
	mockStore.getErr = store.ErrNotFound
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Should not panic or error
	controller.deleteSession(context.Background(), "nonexistent", "expired")

	// No assertion needed - just ensure no panic
}

// Test deleteSession handles delete errors
func TestController_DeleteSession_DeleteError(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Create session
	sessionID := "default-test-CodeInterpreter"
	mockStore.sandboxes[sessionID] = &store.SandboxInfo{
		SessionID: sessionID,
		Namespace: "default",
		Name:      "test",
		Kind:      "CodeInterpreter",
	}

	// Set delete error
	mockStore.deleteErr = assert.AnError

	// Should not panic
	controller.deleteSession(context.Background(), sessionID, "expired")

	// Session should still exist
	_, exists := mockStore.sandboxes[sessionID]
	assert.True(t, exists)
}

// Test NewController with zero workers
func TestNewController_ZeroWorkers(t *testing.T) {
	controller := NewController(nil, 15*time.Minute, 30*time.Second, 0)
	assert.Equal(t, defaultWorkerCount, controller.workerCount)
}

// Test NewController with negative workers
func TestNewController_NegativeWorkers(t *testing.T) {
	controller := NewController(nil, 15*time.Minute, 30*time.Second, -5)
	assert.Equal(t, defaultWorkerCount, controller.workerCount)
}

// Test controller lifecycle (Start/Stop)
func TestController_Lifecycle(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Start controller
	controller.Start()

	// Give it a moment to start
	time.Sleep(100 * time.Millisecond)

	// Stop controller
	controller.Stop()

	// No panic = success
}

// Test custom configuration
func TestNewController_CustomConfig(t *testing.T) {
	timeout := 30 * time.Minute
	requeue := 60 * time.Second
	workers := 10

	controller := NewController(nil, timeout, requeue, workers)

	assert.Equal(t, timeout, controller.sessionTimeout)
	assert.Equal(t, requeue, controller.requeueInterval)
	assert.Equal(t, workers, controller.workerCount)
}

// Test GetMetrics
func TestController_GetMetrics(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	metrics := controller.GetMetrics()
	assert.NotZero(t, metrics.LastReconcileTime)
}

// Test limit parameter in ListExpiredSandboxes
func TestController_Reconcile_RespectsLimit(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Create many expired sessions
	for i := 0; i < 200; i++ {
		sessionID := fmt.Sprintf("default-expired-%d-CodeInterpreter", i)
		mockStore.sandboxes[sessionID] = &store.SandboxInfo{
			SessionID:      sessionID,
			Namespace:      "default",
			Name:           fmt.Sprintf("expired-%d", i),
			Kind:           "CodeInterpreter",
			ExpiresAt:      time.Now().Add(-time.Hour),
			LastActivityAt: time.Now().Add(-2 * time.Hour),
			CreatedAt:      time.Now().Add(-3 * time.Hour),
		}
	}

	// Reconcile (should only delete up to limit)
	controller.reconcile()

	// Verify some sessions were deleted (exact count depends on implementation)
	// In this case, we limit to 100 per query, so at least 100 should be deleted
	assert.Less(t, len(mockStore.sandboxes), 200, "Some sessions should be deleted")
}

