package main

import (
	"context"
	"fmt"
	"testing"
	"time"

	"github.com/agentcube/agentcube/pkg/store"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// MockStore implements store.Store for testing agentd
type MockStore struct {
	sandboxes       map[string]*store.SandboxInfo
	pingErr         error
	getErr          error
	deleteErr       error
	listExpiredErr  error
	listInactiveErr error
}

func NewMockStore() *MockStore {
	return &MockStore{
		sandboxes: make(map[string]*store.SandboxInfo),
	}
}

func (m *MockStore) Ping(ctx context.Context) error {
	return m.pingErr
}

func (m *MockStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*store.SandboxInfo, error) {
	if m.getErr != nil {
		return nil, m.getErr
	}
	if sandbox, ok := m.sandboxes[sessionID]; ok {
		return sandbox, nil
	}
	return nil, store.ErrNotFound
}

func (m *MockStore) StoreSandbox(ctx context.Context, sandbox *store.SandboxInfo) error {
	m.sandboxes[sandbox.SessionID] = sandbox
	return nil
}

func (m *MockStore) UpdateSandbox(ctx context.Context, sandbox *store.SandboxInfo) error {
	m.sandboxes[sandbox.SessionID] = sandbox
	return nil
}

func (m *MockStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	if m.deleteErr != nil {
		return m.deleteErr
	}
	delete(m.sandboxes, sessionID)
	return nil
}

func (m *MockStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	if m.listExpiredErr != nil {
		return nil, m.listExpiredErr
	}
	var expired []string
	for id, sandbox := range m.sandboxes {
		if sandbox.ExpiresAt.Before(before) {
			expired = append(expired, id)
			if len(expired) >= limit {
				break
			}
		}
	}
	return expired, nil
}

func (m *MockStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	if m.listInactiveErr != nil {
		return nil, m.listInactiveErr
	}
	var inactive []string
	for id, sandbox := range m.sandboxes {
		if sandbox.LastActivityAt.Before(before) {
			inactive = append(inactive, id)
			if len(inactive) >= limit {
				break
			}
		}
	}
