// Test IsExpired function
func TestController_IsExpired(t *testing.T) {
	controller := NewController(nil, 15*time.Minute, 30*time.Second, 1)

	// Test expired session
	expiredActivity := time.Now().Add(-20 * time.Minute)
	assert.True(t, controller.IsExpired(expiredActivity), "Session should be expired")

	// Test active session
	activeActivity := time.Now().Add(-5 * time.Minute)
	assert.False(t, controller.IsExpired(activeActivity), "Session should not be expired")

	// Test session at exactly the timeout
	exactActivity := time.Now().Add(-15 * time.Minute)
	assert.False(t, controller.IsExpired(exactActivity), "Session at exact timeout should not be expired")
}

// Test ParseLastActivity
func TestParseLastActivity(t *testing.T) {
	// Valid RFC3339 timestamp
	timestamp := "2024-01-15T10:30:00Z"
	parsed, err := ParseLastActivity(timestamp)
	require.NoError(t, err)
	assert.Equal(t, 2024, parsed.Year())
	assert.Equal(t, 1, parsed.Month())
	assert.Equal(t, 15, parsed.Day())
	assert.Equal(t, 10, parsed.Hour())
	assert.Equal(t, 30, parsed.Minute())

	// Invalid timestamp
	_, err = ParseLastActivity("invalid")
	assert.Error(t, err)

	// Empty timestamp
	_, err = ParseLastActivity("")
	assert.Error(t, err)
}

// Test FormatLastActivity
func TestFormatLastActivity(t *testing.T) {
	now := time.Date(2024, 1, 15, 10, 30, 0, 0, time.UTC)
	formatted := FormatLastActivity(now)
	assert.Equal(t, "2024-01-15T10:30:00Z", formatted)
}

// Test reconcile doesn't delete active sessions
func TestController_Reconcile_SkipsActiveSessions(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Create an active session
	sessionID := "default-active-CodeInterpreter"
	mockStore.sandboxes[sessionID] = &store.SandboxInfo{
