// Test limit parameter in ListExpiredSandboxes
func TestController_Reconcile_RespectsLimit(t *testing.T) {
	mockStore := NewMockStore()
	controller := NewController(mockStore, 15*time.Minute, 30*time.Second, 1)

	// Create many expired sessions
	for i := 0; i < 200; i++ {
		sessionID := fmt.Sprintf("default-expired-%d-CodeInterpreter", i)
		mockStore.sandboxes[sessionID] = &store.SandboxInfo{
			SessionID:      sessionID,
