// ResolveSession resolves a session from the header or creates a new one.
func (sm *SessionManager) ResolveSession(ctx context.Context, namespace, name, kind string, sessionID string) (*SandboxInfo, error) {
	// If session ID provided, try to load from store
	if sessionID != "" {
